      $this-\u003eedebug(","                'Connection: stream_socket_client not available, falling back to fsockopen',","                self::DEBUG_CONNECTION","            );","            set_error_handler(function () {","                call_user_func_array([$this, 'errorHandler'], func_get_args());","            });","            $connection = fsockopen(","                $host,","                $port,","                $errno,","                $errstr,","                $timeout","            );","        }","        restore_error_handler();","","        //Verify we connected properly","        if (!is_resource($connection)) {","            $this-\u003esetError(","                'Failed to connect to server',","                '',","                (string) $errno,","                $errstr","            );","            $this-\u003eedebug(","                'SMTP ERROR: ' . $this-\u003eerror['error']","                . \": $errstr ($errno)\",","                self::DEBUG_CLIENT","            );","","            return false;","        }","","        //SMTP server can take longer to respond, give longer timeout for first read","        //Windows does not have support for this timeout function","        if (strpos(PHP_OS, 'WIN') !== 0) {","            $max = (int)ini_get('max_execution_time');","            //Don't bother if unlimited, or if set_time_limit is disabled","            if (0 !== $max \u0026\u0026 $timeout \u003e $max \u0026\u0026 strpos(ini_get('disable_functions'), 'set_time_limit') === false) {","                @set_time_limit($timeout);","            }","            stream_set_timeout($connection, $timeout, 0);","        }","","        return $connection;","    }","","    /**","     * Initiate a TLS (encrypted) session.","     *","     * @return bool","     */","    public function startTLS()","    {","        if (!$this-\u003esendCommand('STARTTLS', 'STARTTLS', 220)) {","            return false;","        }","","        //Allow the best TLS version(s) we can","        $crypto_method = STREAM_CRYPTO_METHOD_TLS_CLIENT;","","        //PHP 5.6.7 dropped inclusion of TLS 1.1 and 1.2 in STREAM_CRYPTO_METHOD_TLS_CLIENT","        //so add them back in manually if we can","        if (defined('STREAM_CRYPTO_METHOD_TLSv1_2_CLIENT')) {","            // phpcs:ignore PHPCompatibility.Constants.NewConstants.stream_crypto_method_tlsv1_2_clientFound","            $crypto_method |= STREAM_CRYPTO_METHOD_TLSv1_2_CLIENT;","            // phpcs:ignore PHPCompatibility.Constants.NewConstants.stream_crypto_method_tlsv1_1_clientFound","            $crypto_method |= STREAM_CRYPTO_METHOD_TLSv1_1_CLIENT;","        }","","        //Begin encrypted connection","            set_error_handler(function () {","                call_user_func_array([$this, 'errorHandler'], func_get_args());","            });","        $crypto_ok = stream_socket_enable_crypto(","            $this-\u003esmtp_conn,","            true,","            $crypto_method","        );","        restore_error_handler();","","        return (bool) $crypto_ok;","    }","","    /**","     * Perform SMTP authentication.","     * Must be run after hello().","     *","     * @see    hello()","     *","     * @param string $username The user name","     * @param string $password The password","     * @param string $authtype The auth type (CRAM-MD5, PLAIN, LOGIN, XOAUTH2)","     * @param OAuthTokenProvider $OAuth An optional OAuthTokenProvider instance for XOAUTH2 authentication","     *","     * @return bool True if successfully authenticated","     */","    public function authenticate(","        $username,","        $password,","        $authtype = null,","        $OAuth = null","    ) {","        if (!$this-\u003eserver_caps) {","            $this-\u003esetError('Authentication is not allowed before HELO/EHLO');","","            return false;","        }","","        if (array_key_exists('EHLO', $this-\u003eserver_caps)) {","            //SMTP extensions are available; try to find a proper authentication method","            if (!array_key_exists('AUTH', $this-\u003eserver_caps)) {","                $this-\u003esetError('Authentication is not allowed at this stage');","                //'at this stage' means that auth may be allowed after the stage changes","                //e.g. after STARTTLS","","                return false;","            }","","            $this-\u003eedebug('Auth method requested: ' . ($authtype ?: 'UNSPECIFIED'), self::DEBUG_LOWLEVEL);","            $this-\u003eedebug(","                'Auth methods available on the server: ' . implode(',', $this-\u003eserver_caps['AUTH']),","                self::DEBUG_LOWLEVEL","            );","","            //If we have requested a specific auth type, check the server supports it before trying others","            if (null !== $authtype \u0026\u0026 !in_array($authtype, $this-\u003eserver_caps['AUTH'], true)) {","                $this-\u003eedebug('Requested auth method not available: ' . $authtype, self::DEBUG_LOWLEVEL);","                $authtype = null;","            }","","            if (empty($authtype)) {","                //If no auth mechanism is specified, attempt to use these, in this order","                //Try CRAM-MD5 first as it's more secure than the others","                foreach (['CRAM-MD5', 'LOGIN', 'PLAIN', 'XOAUTH2'] as $method) {","                    if (in_array($method, $this-\u003eserver_caps['AUTH'], true)) {","                        $authtype = $method;","                        break;","                    }","                }","                if (empty($authtype)) {","                    $this-\u003esetError('No supported authentication methods found');","","                    return false;","                }","                $this-\u003eedebug('Auth method selected: ' . $authtype, self::DEBUG_LOWLEVEL);","            }","","            if (!in_array($authtype, $this-\u003eserver_caps['AUTH'], true)) {","                $this-\u003esetError(\"The requested authentication method \\\"$authtype\\\" is not supported by the server\");","","                return false;","            }","        } elseif (empty($authtype)) {","            $authtype = 'LOGIN';","        }","        switch ($authtype) {","            case 'PLAIN':","                //Start authentication","                if (!$this-\u003esendCommand('AUTH', 'AUTH PLAIN', 334)) {","                    return false;","                }","                //Send encoded username and password","                if (","                    //Format from https://www.rfc-editor.org/rfc/rfc4616#section-2","                    //We skip the first field (it's forgery), so the string starts with a null byte","                    !$this-\u003esendCommand(","                        'User \u0026 Password',","                        base64_encode(\"\\0\" . $username . \"\\0\" . $password),","                        235","                    )","                ) {","                    return false;","                }","                break;","            case 'LOGIN':","                //Start authentication","                if (!$this-\u003esendCommand('AUTH', 'AUTH LOGIN', 334)) {","                    return false;","                }","                if (!$this-\u003esendCommand('Username', base64_encode($username), 334)) {","                    return false;","                }","                if (!$this-\u003esendCommand('Password', base64_encode($password), 235)) {","                    return false;","                }","                break;","            case 'CRAM-MD5':","                //Start authentication","                if (!$this-\u003esendCommand('AUTH CRAM-MD5', 'AUTH CRAM-MD5', 334)) {","                    return false;","                }","                //Get the challenge","                $challenge = base64_decode(substr($this-\u003elast_reply, 4));","","                //Build the response","                $response = $username . ' ' . $this-\u003ehmac($challenge, $password);","","                //send encoded credentials","                return $this-\u003esendCommand('Username', base64_encode($response), 235);","            case 'XOAUTH2':","                //The OAuth instance must be set up prior to requesting auth.","                if (null === $OAuth) {","                    return false;","                }","                try {","                    $oauth = $OAuth-\u003egetOauth64();","                } catch (\\Exception $e) {","                    // We catch all exceptions and convert them to PHPMailer exceptions to be able to","                    // handle them correctly later","                    throw new Exception(\"SMTP authentication error\", 0, $e);","                }","                /*","                 * An SMTP command line can have a maximum length of 512 bytes, including the command name,","                 * so the base64-encoded OAUTH token has a maximum length of:","                 * 512 - 13 (AUTH XOAUTH2) - 2 (CRLF) = 497 bytes","                 * If the token is longer than that, the command and the token must be sent separately as described in","                 * https://www.rfc-editor.org/rfc/rfc4954#section-4","                 */","                if ($oauth === '') {","                    //Sending an empty auth token is legitimate, but it must be encoded as '='","                    //to indicate it's not a 2-part command","                    if (!$this-\u003esendCommand('AUTH', 'AUTH XOAUTH2 =', 235)) {","                        return false;","                    }","                } elseif (strlen($oauth) \u003c= 497) {","                    //Authenticate using a token in the initial-response part","                    if (!$this-\u003esendCommand('AUTH', 'AUTH XOAUTH2 ' . $oauth, 235)) {","                        return false;","                    }","                } else {","                    //The token is too long, so we need to send it in two parts.","                    //Send the auth command without a token and expect a 334","                    if (!$this-\u003esendCommand('AUTH', 'AUTH XOAUTH2', 334)) {","                        return false;","                    }","                    //Send the token","                    if (!$this-\u003esendCommand('OAuth TOKEN', $oauth, [235, 334])) {","                        return false;","                    }","                    //If the server answers with 334, send an empty line and wait for a 235","                    if (","                        substr($this-\u003elast_reply, 0, 3) === '334'","                        \u0026\u0026 $this-\u003esendCommand('AUTH End', '', 235)","                    ) {","                        return false;","                    }","                }","                break;","            default:","                $this-\u003esetError(\"Authentication method \\\"$authtype\\\" is not supported\");","","                return false;","        }","","        return true;","    }","","    /**","     * Calculate an MD5 HMAC hash.","     * Works like hash_hmac('md5', $data, $key)","     * in case that function is not available.","     *","     * @param string $data The data to hash","     * @param string $key  The key to hash with","     *","     * @return string","     */","    protected function hmac($data, $key)","    {","        if (function_exists('hash_hmac')) {","            return hash_hmac('md5', $data, $key);","        }","","        //The following borrowed from","        //https://www.php.net/manual/en/function.mhash.php#27225","","        //RFC 2104 HMAC implementation for php.","        //Creates an md5 HMAC.","        //Eliminates the need to install mhash to compute a HMAC","        //by Lance Rushing","","        $bytelen = 64; //byte length for md5","        if (strlen($key) \u003e $bytelen) {","            $key = pack('H*', md5($key));","        }","        $key = str_pad($key, $bytelen, chr(0x00));","        $ipad = str_pad('', $bytelen, chr(0x36));","        $opad = str_pad('', $bytelen, chr(0x5c));","        $k_ipad = $key ^ $ipad;","        $k_opad = $key ^ $opad;","","        return md5($k_opad . pack('H*', md5($k_ipad . $data)));","    }","","    /**","     * Check connection state.","     *","     * @return bool True if connected","     */","    public function connected()","    {","        if (is_resource($this-\u003esmtp_conn)) {","            $sock_status = stream_get_meta_data($this-\u003esmtp_conn);","            if ($sock_status['eof']) {","                //The socket is valid but we are not connected","                $this-\u003eedebug(","                    'SMTP NOTICE: EOF caught while checking if connected',","                    self::DEBUG_CLIENT","                );","                $this-\u003eclose();","","                return false;","            }","","            return true; //everything looks good","        }","","        return false;","    }","","    /**","     * Close the socket and clean up the state of the class.","     * Don't use this function without first trying to use QUIT.","     *","     * @see quit()","     */","    public function close()","    {","        $this-\u003eserver_caps = null;","        $this-\u003ehelo_rply = null;","        if (is_resource($this-\u003esmtp_conn)) {","            //Close the connection and cleanup","            fclose($this-\u003esmtp_conn);","            $this-\u003esmtp_conn = null; //Makes for cleaner serialization","            $this-\u003eedebug('Connection: closed', self::DEBUG_CONNECTION);","        }","    }","","    private function iterateLines($s)","    {","        $start = 0;","        $length = strlen($s);","","        for ($i = 0; $i \u003c $length; $i++) {","            $c = $s[$i];","            if ($c === \"\\n\" || $c === \"\\r\") {","                yield substr($s, $start, $i - $start);","                if ($c === \"\\r\" \u0026\u0026 $i + 1 \u003c $length \u0026\u0026 $s[$i + 1] === \"\\n\") {","                    $i++;","                }","                $start = $i + 1;","            }","        }","","        yield substr($s, $start);","    }","","    /**","     * Send an SMTP DATA command.","     * Issues a data command and sends the msg_data to the server,","     * finalizing the mail transaction. $msg_data is the message","     * that is to be sent with the headers. Each header needs to be","     * on a single line followed by a \u003cCRLF\u003e with the message headers","     * and the message body being separated by an additional \u003cCRLF\u003e.","     * Implements RFC 821: DATA \u003cCRLF\u003e.","     *","     * @param string $msg_data Message data to send","     *","     * @return bool","     */","    public function data($msg_data)","    {","        //This will use the standard timelimit","        if (!$this-\u003esendCommand('DATA', 'DATA', 354)) {","            return false;","        }","","        /* The server is ready to accept data!","         * According to rfc821 we should not send more than 1000 characters on a single line (including the LE)","         * so we will break the data up into lines by \\r and/or \\n then if needed we will break each of those into","         * smaller lines to fit within the limit.","         * We will also look for lines that start with a '.' and prepend an additional '.'.","         * NOTE: this does not count towards line-length limit.","         */","","        //Iterate over lines with normalized line breaks","        $lines = $this-\u003eiterateLines($msg_data);","","        /* To distinguish between a complete RFC822 message and a plain message body, we check if the first field","         * of the first line (':' separated) does not contain a space then it _should_ be a header, and we will","         * process all lines before a blank line as headers.","         */","","        $first_line = $lines-\u003ecurrent();","        $field = substr($first_line, 0, strpos($first_line, ':'));","        $in_headers = false;","        if (!empty($field) \u0026\u0026 strpos($field, ' ') === false) {","            $in_headers = true;","        }","","        foreach ($lines as $line) {","            $lines_out = [];","            if ($in_headers \u0026\u0026 $line === '') {","                $in_headers = false;","            }","            //Break this line up into several smaller lines if it's too long","            //Micro-optimisation: isset($str[$len]) is faster than (strlen($str) \u003e $len),","            while (isset($line[self::MAX_LINE_LENGTH])) {","                //Working backwards, try to find a space within the last MAX_LINE_LENGTH chars of the line to break on","                //so as to avoid breaking in the middle of a word","                $pos = strrpos(substr($line, 0, self::MAX_LINE_LENGTH), ' ');","                //Deliberately matches both false and 0","                if (!$pos) {","                    //No nice break found, add a hard break","                    $pos = self::MAX_LINE_LENGTH - 1;","                    $lines_out[] = substr($line, 0, $pos);","                    $line = substr($line, $pos);","                } else {","                    //Break at the found point","                    $lines_out[] = substr($line, 0, $pos);","                    //Move along by the amount we dealt with","                    $line = substr($line, $pos + 1);","                }","                //If processing headers add a LWSP-char to the front of new line RFC822 section 3.1.1","                if ($in_headers) {","                    $line = \"\\t\" . $line;","                }","            }","            $lines_out[] = $line;","","            //Send the lines to the server","            foreach ($lines_out as $line_out) {","                //Dot-stuffing as per RFC5321 section 4.5.2","                //https://www.rfc-editor.org/rfc/rfc5321#section-4.5.2","                if (!empty($line_out) \u0026\u0026 $line_out[0] === '.') {","                    $line_out = '.' . $line_out;","                }","                $this-\u003eclient_send($line_out . static::LE, 'DATA');","            }","        }","","        //Message data has been sent, complete the command","        //Increase timelimit for end of DATA command","        $savetimelimit = $this-\u003eTimelimit;","        $this-\u003eTimelimit *= 2;","        $result = $this-\u003esendCommand('DATA END', '.', 250);","        $this-\u003erecordLastTransactionID();","        //Restore timelimit","        $this-\u003eTimelimit = $savetimelimit;","","        return $result;","    }","","    /**","     * Send an SMTP HELO or EHLO command.","     * Used to identify the sending server to the receiving server.","     * This makes sure that client and server are in a known state.","     * Implements RFC 821: HELO \u003cSP\u003e \u003cdomain\u003e \u003cCRLF\u003e","     * and RFC 2821 EHLO.","     *","     * @param string $host The host name or IP to connect to","     *","     * @return bool","     */","    public function hello($host = '')","    {","        //Try extended hello first (RFC 2821)","        if ($this-\u003esendHello('EHLO', $host)) {","            return true;","        }","","        //Some servers shut down the SMTP service here (RFC 5321)","        if (substr($this-\u003ehelo_rply, 0, 3) == '421') {","            return false;","        }","","        return $this-\u003esendHello('HELO', $host);","    }","","    /**","     * Send an SMTP HELO or EHLO command.","     * Low-level implementation used by hello().","     *","     * @param string $hello The HELO string","     * @param string $host  The hostname to say we are","     *","     * @return bool","     *","     * @see hello()","     */","    protected function sendHello($hello, $host)","    {","        $noerror = $this-\u003esendCommand($hello, $hello . ' ' . $host, 250);","        $this-\u003ehelo_rply = $this-\u003elast_reply;","        if ($noerror) {","            $this-\u003eparseHelloFields($hello);","        } else {","            $this-\u003eserver_caps = null;","        }","","        return $noerror;","    }","","    /**","     * Parse a reply to HELO/EHLO command to discover server extensions.","     * In case of HELO, the only parameter that can be discovered is a server name.","     *","     * @param string $type `HELO` or `EHLO`","     */","    protected function parseHelloFields($type)","    {","        $this-\u003eserver_caps = [];","        $lines = explode(\"\\n\", $this-\u003ehelo_rply);","","        foreach ($lines as $n =\u003e $s) {","            //First 4 chars contain response code followed by - or space","            $s = trim(substr($s, 4));","            if (empty($s)) {","                continue;","            }","            $fields = explode(' ', $s);","            if (!empty($fields)) {","                if (!$n) {","                    $name = $type;","                    $fields = $fields[0];","                } else {","                    $name = array_shift($fields);","                    switch ($name) {","                        case 'SIZE':","                            $fields = ($fields ? $fields[0] : 0);","                            break;","                        case 'AUTH':","                            if (!is_array($fields)) {","                                $fields = [];","                            }","                            break;","                        default:","                            $fields = true;","                    }","                }","                $this-\u003eserver_caps[$name] = $fields;","            }","        }","    }","","    /**","     * Send an SMTP MAIL command.","     * Starts a mail transaction from the email address specified in","     * $from. Returns true if successful or false otherwise. If True","     * the mail transaction is started and then one or more recipient","     * commands may be called followed by a data command.","     * Implements RFC 821: MAIL \u003cSP\u003e FROM:\u003creverse-path\u003e \u003cCRLF\u003e and","     * two extensions, namely XVERP and SMTPUTF8.","     *","     * The server's EHLO response is not checked. If use of either","     * extensions is enabled even though the server does not support","     * that, mail submission will fail.","     *","     * XVERP is documented at https://www.postfix.org/VERP_README.html","     * and SMTPUTF8 is specified in RFC 6531.","     *","     * @param string $from Source address of this message","     *","     * @return bool","     */","    public function mail($from)","    {","        $useVerp = ($this-\u003edo_verp ? ' XVERP' : '');","        $useSmtputf8 = ($this-\u003edo_smtputf8 ? ' SMTPUTF8' : '');","","        return $this-\u003esendCommand(","            'MAIL FROM',","            'MAIL FROM:\u003c' . $from . '\u003e' . $useSmtputf8 . $useVerp,","            250","        );","    }","","    /**","     * Send an SMTP QUIT command.","     * Closes the socket if there is no error or the $close_on_error argument is true.","     * Implements from RFC 821: QUIT \u003cCRLF\u003e.","     *","     * @param bool $close_on_error Should the connection close if an error occurs?","     *","     * @return bool","     */","    public function quit($close_on_error = true)","    {","        $noerror = $this-\u003esendCommand('QUIT', 'QUIT', 221);","        $err = $this-\u003eerror; //Save any error","        if ($noerror || $close_on_error) {","            $this-\u003eclose();","            $this-\u003eerror = $err; //Restore any error from the quit command","        }","","        return $noerror;","    }","","    /**","     * Send an SMTP RCPT command.","     * Sets the TO argument to $toaddr.","     * Returns true if the recipient was accepted false if it was rejected.","     * Implements from RFC 821: RCPT \u003cSP\u003e TO:\u003cforward-path\u003e \u003cCRLF\u003e.","     *","     * @param string $address The address the message is being sent to","     * @param string $dsn     Comma separated list of DSN notifications. NEVER, SUCCESS, FAILURE","     *                        or DELAY. If you specify NEVER all other notifications are ignored.","     *","     * @return bool","     */","    public function recipient($address, $dsn = '')","    {","        if (empty($dsn)) {","            $rcpt = 'RCPT TO:\u003c' . $address . '\u003e';","        } else {","            $dsn = strtoupper($dsn);","            $notify = [];","","            if (strpos($dsn, 'NEVER') !== false) {","                $notify[] = 'NEVER';","            } else {","                foreach (['SUCCESS', 'FAILURE', 'DELAY'] as $value) {","                    if (strpos($dsn, $value) !== false) {","                        $notify[] = $value;","                    }","                }","            }","","            $rcpt = 'RCPT TO:\u003c' . $address . '\u003e NOTIFY=' . implode(',', $notify);","        }","","        return $this-\u003esendCommand(","            'RCPT TO',","            $rcpt,","            [250, 251]","        );","    }","","    /**","     * Send SMTP XCLIENT command to server and check its return code.","     *","     * @return bool True on success","     */","    public function xclient(array $vars)","    {","        $xclient_options = \"\";","        foreach ($vars as $key =\u003e $value) {","            if (in_array($key, SMTP::$xclient_allowed_attributes)) {","                $xclient_options .= \" {$key}={$value}\";","            }","        }","        if (!$xclient_options) {","            return true;","        }","        return $this-\u003esendCommand('XCLIENT', 'XCLIENT' . $xclient_options, 250);","    }","","    /**","     * Send an SMTP RSET command.","     * Abort any transaction that is currently in progress.","     * Implements RFC 821: RSET \u003cCRLF\u003e.","     *","     * @return bool True on success","     */","    public function reset()","    {","        return $this-\u003esendCommand('RSET', 'RSET', 250);","    }","","    /**","     * Send a command to an SMTP server and check its return code.","     *","     * @param string    $command       The command name - not sent to the server","     * @param string    $commandstring The actual command to send","     * @param int|array $expect        One or more expected integer success codes","     *","     * @return bool True on success","     */","    protected function sendCommand($command, $commandstring, $expect)","    {","        if (!$this-\u003econnected()) {","            $this-\u003esetError(\"Called $command without being connected\");","","            return false;","        }","        //Reject line breaks in all commands","        if ((strpos($commandstring, \"\\n\") !== false) || (strpos($commandstring, \"\\r\") !== false)) {","            $this-\u003esetError(\"Command '$command' contained line breaks\");","","            return false;","        }","        $this-\u003eclient_send($commandstring . static::LE, $command);","","        $this-\u003elast_reply = $this-\u003eget_lines();","        //Fetch SMTP code and possible error code explanation","        $matches = [];","        if (preg_match('/^([\\d]{3})[ -](?:([\\d]\\\\.[\\d]\\\\.[\\d]{1,2}) )?/', $this-\u003elast_reply, $matches)) {","            $code = (int) $matches[1];","            $code_ex = (count($matches) \u003e 2 ? $matches[2] : null);","            //Cut off error code from each response line","            $detail = preg_replace(","                \"/{$code}[ -]\" .","                ($code_ex ? str_replace('.', '\\\\.', $code_ex) . ' ' : '') . '/m',","                '',","                $this-\u003elast_reply","            );","        } else {","            //Fall back to simple parsing if regex fails","            $code = (int) substr($this-\u003elast_reply, 0, 3);","            $code_ex = null;","            $detail = substr($this-\u003elast_reply, 4);","        }","","        $this-\u003eedebug('SERVER -\u003e CLIENT: ' . $this-\u003elast_reply, self::DEBUG_SERVER);","","        if (!in_array($code, (array) $expect, true)) {","            $this-\u003esetError(","                \"$command command failed\",","                $detail,","                $code,","                $code_ex","            );","            $this-\u003eedebug(","                'SMTP ERROR: ' . $this-\u003eerror['error'] . ': ' . $this-\u003elast_reply,","                self::DEBUG_CLIENT","            );","","            return false;","        }","","        //Don't clear the error store when using keepalive","        if ($command !== 'RSET') {","            $this-\u003esetError('');","        }","","        return true;","    }","","    /**","     * Send an SMTP SAML command.","     * Starts a mail transaction from the email address specified in $from.","     * Returns true if successful or false otherwise. If True","     * the mail transaction is started and then one or more recipient","     * commands may be called followed by a data command. This command","     * will send the message to the users terminal if they are logged","     * in and send them an email.","     * Implements RFC 821: SAML \u003cSP\u003e FROM:\u003creverse-path\u003e \u003cCRLF\u003e.","     *","     * @param string $from The address the message is from","     *","     * @return bool","     */","    public function sendAndMail($from)","    {","        return $this-\u003esendCommand('SAML', \"SAML FROM:$from\", 250);","    }","","    /**","     * Send an SMTP VRFY command.","     *","     * @param string $name The name to verify","     *","     * @return bool","     */","    public function verify($name)","    {","        return $this-\u003esendCommand('VRFY', \"VRFY $name\", [250, 251]);","    }","","    /**","     * Send an SMTP NOOP command.","     * Used to keep keep-alives alive, doesn't actually do anything.","     *","     * @return bool","     */","    public function noop()","    {","        return $this-\u003esendCommand('NOOP', 'NOOP', 250);","    }","","    /**","     * Send an SMTP TURN command.","     * This is an optional command for SMTP that this class does not support.","     * This method is here to make the RFC821 Definition complete for this class","     * and _may_ be implemented in future.","     * Implements from RFC 821: TURN \u003cCRLF\u003e.","     *","     * @return bool","     */","    public function turn()","    {","        $this-\u003esetError('The SMTP TURN command is not implemented');","        $this-\u003eedebug('SMTP NOTICE: ' . $this-\u003eerror['error'], self::DEBUG_CLIENT);","","        return false;","    }","","    /**","     * Send raw data to the server.","     *","     * @param string $data    The data to send","     * @param string $command Optionally, the command this is part of, used only for controlling debug output","     *","     * @return int|bool The number of bytes sent to the server or false on error","     */","    public function client_send($data, $command = '')","    {","        //If SMTP transcripts are left enabled, or debug output is posted online","        //it can leak credentials, so hide credentials in all but lowest level","        if (","            self::DEBUG_LOWLEVEL \u003e $this-\u003edo_debug \u0026\u0026","            in_array($command, ['User \u0026 Password', 'Username', 'Password'], true)","        ) {","            $this-\u003eedebug('CLIENT -\u003e SERVER: [credentials hidden]', self::DEBUG_CLIENT);","        } else {","            $this-\u003eedebug('CLIENT -\u003e SERVER: ' . $data, self::DEBUG_CLIENT);","        }","        set_error_handler(function () {","            call_user_func_array([$this, 'errorHandler'], func_get_args());","        });","        $result = fwrite($this-\u003esmtp_conn, $data);","        restore_error_handler();","","        return $result;","    }","","    /**","     * Get the latest error.","     *","     * @return array","     */","    public function getError()","    {","        return $this-\u003eerror;","    }","","    /**","     * Get SMTP extensions available on the server.","     *","     * @return array|null","     */","    public function getServerExtList()","    {","        return $this-\u003eserver_caps;","    }","","    /**","     * Get metadata about the SMTP server from its HELO/EHLO response.","     * The method works in three ways, dependent on argument value and current state:","     *   1. HELO/EHLO has not been sent - returns null and populates $this-\u003eerror.","     *   2. HELO has been sent -","     *     $name == 'HELO': returns server name","     *     $name == 'EHLO': returns boolean false","     *     $name == any other string: returns null and populates $this-\u003eerror","     *   3. EHLO has been sent -","     *     $name == 'HELO'|'EHLO': returns the server name","     *     $name == any other string: if extension $name exists, returns True","     *       or its options (e.g. AUTH mechanisms supported). Otherwise returns False.","     *","     * @param string $name Name of SMTP extension or 'HELO'|'EHLO'","     *","     * @return string|bool|null","     */","    public function getServerExt($name)","    {","        if (!$this-\u003eserver_caps) {","            $this-\u003esetError('No HELO/EHLO was sent');","","            return null;","        }","","        if (!array_key_exists($name, $this-\u003eserver_caps)) {","            if ('HELO' === $name) {","                return $this-\u003eserver_caps['EHLO'];","            }","            if ('EHLO' === $name || array_key_exists('EHLO', $this-\u003eserver_caps)) {","                return false;","            }","            $this-\u003esetError('HELO handshake was used; No information about server extensions available');","","            return null;","        }","","        return $this-\u003eserver_caps[$name];","    }","","    /**","     * Get the last reply from the server.","     *","     * @return string","     */","    public function getLastReply()","    {","        return $this-\u003elast_reply;","    }","","    /**","     * Read the SMTP server's response.","     * Either before eof or socket timeout occurs on the operation.","     * With SMTP we can tell if we have more lines to read if the","     * 4th character is '-' symbol. If it is a space then we don't","     * need to read anything else.","     *","     * @return string","     */","    protected function get_lines()","    {","        //If the connection is bad, give up straight away","        if (!is_resource($this-\u003esmtp_conn)) {","            return '';","        }","        $data = '';","        $endtime = 0;","        stream_set_timeout($this-\u003esmtp_conn, $this-\u003eTimeout);","        if ($this-\u003eTimelimit \u003e 0) {","            $endtime = time() + $this-\u003eTimelimit;","        }","        $selR = [$this-\u003esmtp_conn];","        $selW = null;","        while (is_resource($this-\u003esmtp_conn) \u0026\u0026 !feof($this-\u003esmtp_conn)) {","            //Must pass vars in here as params are by reference","            //solution for signals inspired by https://github.com/symfony/symfony/pull/6540","            set_error_handler(function () {","                call_user_func_array([$this, 'errorHandler'], func_get_args());","            });","            $n = stream_select($selR, $selW, $selW, $this-\u003eTimelimit);","            restore_error_handler();","","            if ($n === false) {","                $message = $this-\u003egetError()['detail'];","","                $this-\u003eedebug(","                    'SMTP -\u003e get_lines(): select failed (' . $message . ')',","                    self::DEBUG_LOWLEVEL","                );","","                //stream_select returns false when the `select` system call is interrupted","                //by an incoming signal, try the select again","                if (","                    stripos($message, 'interrupted system call') !== false ||","                    (","                        // on applications with a different locale than english, the message above is not found because","                        // it's translated. So we also check for the SOCKET_EINTR constant which is defined under","                        // Windows and UNIX-like platforms (if available on the platform).","                        defined('SOCKET_EINTR') \u0026\u0026","                        stripos($message, 'stream_select(): Unable to select [' . SOCKET_EINTR . ']') !== false","                    )","                ) {","                    $this-\u003eedebug(","                        'SMTP -\u003e get_lines(): retrying stream_select',","                        self::DEBUG_LOWLEVEL","                    );","                    $this-\u003esetError('');","                    continue;","                }","","                break;","            }","","            if (!$n) {","                $this-\u003eedebug(","                    'SMTP -\u003e get_lines(): select timed-out in (' . $this-\u003eTimelimit . ' sec)',","                    self::DEBUG_LOWLEVEL","                );","                break;","            }","","            //Deliberate noise suppression - errors are handled afterwards","            $str = @fgets($this-\u003esmtp_conn, self::MAX_REPLY_LENGTH);","            $this-\u003eedebug('SMTP INBOUND: \"' . trim($str) . '\"', self::DEBUG_LOWLEVEL);","            $data .= $str;","            //If response is only 3 chars (not valid, but RFC5321 S4.2 says it must be handled),","            //or 4th character is a space or a line break char, we are done reading, break the loop.","            //String array access is a significant micro-optimisation over strlen","            if (!isset($str[3]) || $str[3] === ' ' || $str[3] === \"\\r\" || $str[3] === \"\\n\") {","                break;","            }","            //Timed-out? Log and break","            $info = stream_get_meta_data($this-\u003esmtp_conn);","            if ($info['timed_out']) {","                $this-\u003eedebug(","                    'SMTP -\u003e get_lines(): stream timed-out (' . $this-\u003eTimeout . ' sec)',","                    self::DEBUG_LOWLEVEL","                );","                break;","            }","            //Now check if reads took too long","            if ($endtime \u0026\u0026 time() \u003e $endtime) {","                $this-\u003eedebug(","                    'SMTP -\u003e get_lines(): timelimit reached (' .","                    $this-\u003eTimelimit . ' sec)',","                    self::DEBUG_LOWLEVEL","                );","                break;","            }","        }","","        return $data;","    }","","    /**","     * Enable or disable VERP address generation.","     *","     * @param bool $enabled","     */","    public function setVerp($enabled = false)","    {","        $this-\u003edo_verp = $enabled;","    }","","    /**","     * Get VERP address generation mode.","     *","     * @return bool","     */","    public function getVerp()","    {","        return $this-\u003edo_verp;","    }","","    /**","     * Enable or disable use of SMTPUTF8.","     *","     * @param bool $enabled","     */","    public function setSMTPUTF8($enabled = false)","    {","        $this-\u003edo_smtputf8 = $enabled;","    }","","    /**","     * Get SMTPUTF8 use.","     *","     * @return bool","     */","    public function getSMTPUTF8()","    {","        return $this-\u003edo_smtputf8;","    }","","    /**","     * Set error messages and codes.","     *","     * @param string $message      The error message","     * @param string $detail       Further detail on the error","     * @param string $smtp_code    An associated SMTP error code","     * @param string $smtp_code_ex Extended SMTP code","     */","    protected function setError($message, $detail = '', $smtp_code = '', $smtp_code_ex = '')","    {","        $this-\u003eerror = [","            'error' =\u003e $message,","            'detail' =\u003e $detail,","            'smtp_code' =\u003e $smtp_code,","            'smtp_code_ex' =\u003e $smtp_code_ex,","        ];","    }","","    /**","     * Set debug output method.","     *","     * @param string|callable $method The name of the mechanism to use for debugging output, or a callable to handle it","     */","    public function setDebugOutput($method = 'echo')","    {","        $this-\u003eDebugoutput = $method;","    }","","    /**","     * Get debug output method.","     *","     * @return string","     */","    public function getDebugOutput()","    {","        return $this-\u003eDebugoutput;","    }","","    /**","     * Set debug output level.","     *","     * @param int $level","     */","    public function setDebugLevel($level = 0)","    {","        $this-\u003edo_debug = $level;","    }","","    /**","     * Get debug output level.","     *","     * @return int","     */","    public function getDebugLevel()","    {","        return $this-\u003edo_debug;","    }","","    /**","     * Set SMTP timeout.","     *","     * @param int $timeout The timeout duration in seconds","     */","    public function setTimeout($timeout = 0)","    {","        $this-\u003eTimeout = $timeout;","    }","","    /**","     * Get SMTP timeout.","     *","     * @return int","     */","    public function getTimeout()","    {","        return $this-\u003eTimeout;","    }","","    /**","     * Reports an error number and string.","     *","     * @param int    $errno   The error number returned by PHP","     * @param string $errmsg  The error message returned by PHP","     * @param string $errfile The file the error occurred in","     * @param int    $errline The line number the error occurred on","     */","    protected function errorHandler($errno, $errmsg, $errfile = '', $errline = 0)","    {","        $notice = 'Connection failed.';","        $this-\u003esetError(","            $notice,","            $errmsg,","            (string) $errno","        );","        $this-\u003eedebug(","            \"$notice Error #$errno: $errmsg [$errfile line $errline]\",","            self::DEBUG_CONNECTION","        );","    }","","    /**","     * Extract and return the ID of the last SMTP transaction based on","     * a list of patterns provided in SMTP::$smtp_transaction_id_patterns.","     * Relies on the host providing the ID in response to a DATA command.","     * If no reply has been received yet, it will return null.","     * If no pattern was matched, it will return false.","     *","     * @return bool|string|null","     */","    protected function recordLastTransactionID()","    {","        $reply = $this-\u003egetLastReply();","","        if (empty($reply)) {","            $this-\u003elast_smtp_transaction_id = null;","        } else {","            $this-\u003elast_smtp_transaction_id = false;","            foreach ($this-\u003esmtp_transaction_id_patterns as $smtp_transaction_id_pattern) {","                $matches = [];","                if (preg_match($smtp_transaction_id_pattern, $reply, $matches)) {","                    $this-\u003elast_smtp_transaction_id = trim($matches[1]);","                    break;","                }","            }","        }","","        return $this-\u003elast_smtp_transaction_id;","    }","","    /**","     * Get the queue/transaction ID of the last SMTP transaction","     * If no reply has been received yet, it will return null.","     * If no pattern was matched, it will return false.","     *","     * @return bool|string|null","     *","     * @see recordLastTransactionID()","     */","    public function getLastTransactionID()","    {","        return $this-\u003elast_smtp_transaction_id;","    }","}"],"stylingDirectives":null,"colorizedLines":["\u003cspan class=pl-ent\u003e\u0026lt;?php\u003c/span\u003e","","\u003cspan class=pl-c\u003e/**\u003c/span\u003e","\u003cspan class=pl-c\u003e * PHPMailer RFC821 SMTP