c/span\u003e =\u0026gt; \u003cspan class=pl-s\u003e\u0026#39;\u003cspan class=pl-s\u003e/[\\d]{3} OK id=(.*)/\u003c/span\u003e\u0026#39;\u003c/span\u003e,","        \u003cspan class=pl-s\u003e\u0026#39;\u003cspan class=pl-s\u003esendmail\u003c/span\u003e\u0026#39;\u003c/span\u003e =\u0026gt; \u003cspan class=pl-s\u003e\u0026#39;\u003cspan class=pl-s\u003e/[\\d]{3} 2\\.0\\.0 (.*) Message/\u003c/span\u003e\u0026#39;\u003c/span\u003e,","        \u003cspan class=pl-s\u003e\u0026#39;\u003cspan class=pl-s\u003epostfix\u003c/span\u003e\u0026#39;\u003c/span\u003e =\u0026gt; \u003cspan class=pl-s\u003e\u0026#39;\u003cspan class=pl-s\u003e/[\\d]{3} 2\\.0\\.0 Ok: queued as (.*)/\u003c/span\u003e\u0026#39;\u003c/span\u003e,","        \u003cspan class=pl-s\u003e\u0026#39;\u003cspan class=pl-s\u003eMicrosoft_ESMTP\u003c/span\u003e\u0026#39;\u003c/span\u003e =\u0026gt; \u003cspan class=pl-s\u003e\u0026#39;\u003cspan class=pl-s\u003e/[0-9]{3} 2\\.[\\d]\\.0 (.*)@(?:.*) Queued mail for delivery/\u003c/span\u003e\u0026#39;\u003c/span\u003e,","        \u003cspan class=pl-s\u003e\u0026#39;\u003cspan class=pl-s\u003eAmazon_SES\u003c/span\u003e\u0026#39;\u003c/span\u003e =\u0026gt; \u003cspan class=pl-s\u003e\u0026#39;\u003cspan class=pl-s\u003e/[\\d]{3} Ok (.*)/\u003c/span\u003e\u0026#39;\u003c/span\u003e,","        \u003cspan class=pl-s\u003e\u0026#39;\u003cspan class=pl-s\u003eSendGrid\u003c/span\u003e\u0026#39;\u003c/span\u003e =\u0026gt; \u003cspan class=pl-s\u003e\u0026#39;\u003cspan class=pl-s\u003e/[\\d]{3} Ok: queued as (.*)/\u003c/span\u003e\u0026#39;\u003c/span\u003e,","        \u003cspan class=pl-s\u003e\u0026#39;\u003cspan class=pl-s\u003eCampaignMonitor\u003c/span\u003e\u0026#39;\u003c/span\u003e =\u0026gt; \u003cspan class=pl-s\u003e\u0026#39;\u003cspan class=pl-s\u003e/[\\d]{3} 2\\.0\\.0 OK:([a-zA-Z\\d]{48})/\u003c/span\u003e\u0026#39;\u003c/span\u003e,","        \u003cspan class=pl-s\u003e\u0026#39;\u003cspan class=pl-s\u003eHaraka\u003c/span\u003e\u0026#39;\u003c/span\u0